// ─── STORAGE ──────────────────────────────────────────────────────────────────
async function saveAll(cards, collections, settings) {
  try {
    const meta = cards.map(({ imageFront, imageBack, ...r }) => r);
    storage.set("cv_meta", JSON.stringify(meta));
    for (const card of cards) {
      if (card.imageFront) storage.set(`cv_f_${card.id}`, card.imageFront);
      if (card.imageBack)  storage.set(`cv_b_${card.id}`, card.imageBack);
    }
    storage.set("cv_collections", JSON.stringify(collections));
    storage.set("cv_settings", JSON.stringify(settings));
  } catch(e) { console.error(e); }
}
async function loadAll() {
  try {
    const metaR = storage.get("cv_meta");
    const colR  = storage.get("cv_collections");
    const setR  = storage.get("cv_settings");
    const meta = metaR ? JSON.parse(metaR.value) : [];
    const cards = meta.map(card => {
      const f = storage.get(`cv_f_${card.id}`);
      const b = storage.get(`cv_b_${card.id}`);
      return {...card, imageFront: f?.value||null, imageBack: b?.value||null};
    });
    const collections = colR ? JSON.parse(colR.value) : [];
    const settings    = setR ? JSON.parse(setR.value) : {};
    return {cards, collections, settings};
  } catch { return {cards:[],collections:[],settings:{}}; }
}

async function fileToImage(file) {
  if (file.type === "application/pdf") {
    return new Promise(resolve => {
      const reader = new FileReader();
      reader.onload = async e => {
        try {
          const lib = window["pdfjs-dist/build/pdf"];
          if (!lib) { resolve(null); return; }
          lib.GlobalWorkerOptions.workerSrc = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js";
          const pdf = await lib.getDocument({data: e.target.result}).promise;
          const page = await pdf.getPage(1);
          const vp = page.getViewport({scale:2.5});
          const canvas = document.createElement("canvas");
          canvas.width=vp.width; canvas.height=vp.height;
          await page.render({canvasContext:canvas.getContext("2d"),viewport:vp}).promise;
          resolve(canvas.toDataURL("image/jpeg",0.92));
        } catch { resolve(null); }
      };
      reader.readAsArrayBuffer(file);
    });
  }
  return new Promise(resolve => { const r=new FileReader(); r.onload=e=>resolve(e.target.result); r.readAsDataURL(file); });
}

