// Minimal SVG logo — diamond vault mark
function VaultMark({ size=32, color="#ffd700" }) {
  return (
    <svg width={size} height={size} viewBox="0 0 32 32" fill="none">
      <polygon points="16,2 30,16 16,30 2,16" stroke={color} strokeWidth="2" fill="none"/>
      <polygon points="16,7 25,16 16,25 7,16" stroke={color} strokeWidth="1.2" fill={color} fillOpacity="0.12"/>
      <circle cx="16" cy="16" r="3" fill={color}/>
    </svg>
  );
}

// Full logo image (for splash/header)
function VaultLogo({ size=48 }) {
  return <img src="/icon.png" alt="César's Vault" style={{width:size,height:size,objectFit:"contain",display:"block"}}/>;
}
function VaultLogoH({ height=52 }) {
  return <img src="/icon.png" alt="César's Vault" style={{height:height,width:"auto",objectFit:"contain",display:"block",maxWidth:"100%"}}/>;
}

// Theme-aware nav icons
function NavIcon({ d, size=22, color }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <path d={d}/>
    </svg>
  );
}

// ─── IMAGE SLOT ───────────────────────────────────────────────────────────────
function ImageSlot({ label, image, onImage, icon, T }) {
  const ref = useRef();
  const [cvt, setCvt] = useState(false);
  const handleFile = async e => {
    const file=e.target.files[0]; if(!file) return;
    setCvt(file.type==="application/pdf");
    const img=await fileToImage(file); setCvt(false);
    if(img) onImage(img); e.target.value="";
  };
  return (
    <div style={{flex:1}}>
      <div style={{fontSize:10,letterSpacing:3,color:T.textMuted,textAlign:"center",marginBottom:6}}>{label}</div>
      <div onClick={()=>ref.current.click()} style={{aspectRatio:"2.5/3.5",border:`2px dashed ${image?T.accent+"55":"#ffffff18"}`,borderRadius:12,overflow:"hidden",cursor:"pointer",position:"relative",background:"#0a0a14",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center"}}>
        {cvt?<div style={{textAlign:"center",color:T.accent,fontSize:12}}><div style={{fontSize:24,marginBottom:6}}>⚙️</div>Convirtiendo...</div>
          :image?<><img src={image} style={{width:"100%",height:"100%",objectFit:"cover"}}/><div style={{position:"absolute",top:6,right:6,background:T.accent+"22",border:`1px solid ${T.accent}55`,borderRadius:6,padding:"2px 7px",fontSize:9,color:T.accent}}>✓</div></>
          :<div style={{textAlign:"center",color:"#3a3a5a",padding:8}}><div style={{fontSize:28,marginBottom:6}}>{icon}</div><div style={{fontSize:10,lineHeight:1.5}}>Cámara · Galería · PDF</div></div>}
      </div>
      <input ref={ref} type="file" accept="image/*,application/pdf" style={{display:"none"}} onChange={handleFile}/>
    </div>
  );
}

// ─── FULL 360° 3D CARD VIEWER ─────────────────────────────────────────────────
// Rotación libre sin límites en X e Y — el reverso aparece naturalmente al girar
function Card360Viewer({ front, back, rarityColor, onClose, name }) {
  const rotRef = useRef({x:-15, y:20});
  const [transform, setTransform] = useState({x:-15, y:20});
  const lastTouchRef = useRef(null);
  const isDraggingRef = useRef(false);
  const velRef = useRef({x:0, y:0});
  const rafRef = useRef(null);
  const autoRaf = useRef(null);

  // Gentle auto-rotate when idle
  const startAutoRotate = () => {
    cancelAnimationFrame(autoRaf.current);
    const go = () => {
      rotRef.current.y += 0.3;
      setTransform({...rotRef.current});
      autoRaf.current = requestAnimationFrame(go);
    };
    autoRaf.current = requestAnimationFrame(go);
  };
  const stopAutoRotate = () => cancelAnimationFrame(autoRaf.current);

  useEffect(() => {
    const timer = setTimeout(startAutoRotate, 2000);
    return () => { clearTimeout(timer); stopAutoRotate(); cancelAnimationFrame(rafRef.current); };
  }, []);

  const onTouchStart = e => {
    stopAutoRotate();
    isDraggingRef.current = true;
    velRef.current = {x:0, y:0};
    lastTouchRef.current = {x:e.touches[0].clientX, y:e.touches[0].clientY};
    cancelAnimationFrame(rafRef.current);
  };
  const onTouchMove = e => {
    if(!isDraggingRef.current || !lastTouchRef.current) return;
    e.preventDefault();
    const dx = e.touches[0].clientX - lastTouchRef.current.x;
    const dy = e.touches[0].clientY - lastTouchRef.current.y;
    velRef.current = {x:dy*0.5, y:dx*0.5};
    rotRef.current.x += dy * 0.5;
    rotRef.current.y += dx * 0.5;
    setTransform({...rotRef.current});
    lastTouchRef.current = {x:e.touches[0].clientX, y:e.touches[0].clientY};
  };
  const onTouchEnd = () => {
    isDraggingRef.current = false;
    // Momentum
    const decel = () => {
      velRef.current.x *= 0.92;
      velRef.current.y *= 0.92;
      rotRef.current.x += velRef.current.x;
      rotRef.current.y += velRef.current.y;
      setTransform({...rotRef.current});
      if(Math.abs(velRef.current.x)>0.05 || Math.abs(velRef.current.y)>0.05) {
        rafRef.current = requestAnimationFrame(decel);
      } else {
        // Resume auto-rotate after 3s idle
        setTimeout(startAutoRotate, 3000);
      }
    };
    rafRef.current = requestAnimationFrame(decel);
  };

  const screenW = typeof window!=="undefined"?window.innerWidth:390;
  const cW = Math.min(screenW*0.75, 310);
  const cH = cW*1.4;

  return (
    <div style={{position:"fixed",inset:0,background:"#000",zIndex:500,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",userSelect:"none"}}>
      {/* Ambient glow */}
      <div style={{position:"absolute",inset:0,background:`radial-gradient(ellipse at 50% 45%,${rarityColor}22 0%,transparent 60%)`,pointerEvents:"none"}}/>
      {/* Close */}
      <button onClick={onClose} style={{position:"absolute",top:"calc(16px + var(--sat, 44px))",left:16,width:38,height:38,borderRadius:"50%",background:"#ffffff14",border:"none",color:"#fff",fontSize:18,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",zIndex:10}}>✕</button>
      <div style={{position:"absolute",top:22,left:0,right:0,textAlign:"center",color:"#ffffff30",fontSize:10,letterSpacing:4,pointerEvents:"none"}}>VISOR 360°</div>

      {/* 3D Stage */}
      <div style={{width:cW,height:cH,perspective:900,cursor:"grab",touchAction:"none"}}
        onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd}>
        <div style={{
          width:"100%", height:"100%", transformStyle:"preserve-3d",
          transform:`rotateX(${transform.x}deg) rotateY(${transform.y}deg)`,
          transition:"none", position:"relative"
        }}>
          {/* Front */}
          <div style={{position:"absolute",inset:0,backfaceVisibility:"hidden",borderRadius:18,overflow:"hidden",boxShadow:`0 30px 80px #00000099,0 0 0 1.5px ${rarityColor}66`}}>
            {front?<img src={front} style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}}/>
              :<div style={{width:"100%",height:"100%",background:"linear-gradient(135deg,#1a1a2e,#0d0d1a)",display:"flex",alignItems:"center",justifyContent:"center"}}><VaultMark size={60}/></div>}
          </div>
          {/* Back */}
          <div style={{position:"absolute",inset:0,backfaceVisibility:"hidden",transform:"rotateY(180deg)",borderRadius:18,overflow:"hidden",boxShadow:`0 30px 80px #00000099,0 0 0 1.5px ${rarityColor}33`}}>
            {back?<img src={back} style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}}/>
              :<div style={{width:"100%",height:"100%",background:"linear-gradient(135deg,#111120,#0a0a16)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:10}}>
                <VaultMark size={60} color="#ffffff30"/>
                <div style={{color:"#ffffff30",fontSize:12,letterSpacing:2}}>SIN REVERSO</div>
              </div>}
          </div>
          {/* Card edge — thickness illusion */}
          <div style={{position:"absolute",inset:0,transform:"translateZ(-2px)",borderRadius:18,background:rarityColor,opacity:0.3,pointerEvents:"none"}}/>
        </div>
      </div>

      {/* Shadow */}
      <div style={{width:cW*0.6,height:16,background:"#000",borderRadius:"50%",filter:"blur(18px)",opacity:0.8,marginTop:8}}/>
      {/* Name */}
      <div style={{color:"#ffffff70",fontSize:14,letterSpacing:1,marginTop:12}}>{name}</div>
      <div style={{color:"#ffffff25",fontSize:10,letterSpacing:3,marginTop:6}}>ARRASTRA PARA ROTAR · AUTO-GIRO AL SOLTAR</div>
    </div>
  );
}

// ─── CARD DETAIL — imagen a pantalla completa, sheet solo al arrastrar ─────────
function CardDetail({ card, onClose, onEdit, onDelete, on3D, rarities, T }) {
  const [sheetOpen, setSheetOpen] = useState(false);
  const [confirmDel, setConfirmDel] = useState(false);
  const sheetRef = useRef();
  const startYRef = useRef(null);
  const rd = rarities.find(r=>r.label===card.rarity) || rarities[0] || {color:"#9a9a9a",label:"—"};
  const glowColor = rd.color;
  const date = card.addedAt ? new Date(card.addedAt).toLocaleDateString("es-ES") : "—";

  const onSheetTouchStart = e => { startYRef.current = e.touches[0].clientY; };
  const onSheetTouchEnd = e => {
    if(startYRef.current===null) return;
    const dy = startYRef.current - e.changedTouches[0].clientY;
    if(dy > 30) setSheetOpen(true);
    if(dy < -30) setSheetOpen(false);
    startYRef.current = null;
  };

  return (
    <div style={{position:"fixed",inset:0,zIndex:300,background:"#000",overflow:"hidden"}}>
      {/* Full-screen card image */}
      <div style={{position:"absolute",inset:0}}>
        {card.imageFront
          ? <img src={card.imageFront} style={{width:"100%",height:"100%",objectFit:"contain",objectPosition:"center 20%",display:"block",background:"#000"}}/>
          : <div style={{width:"100%",height:"100%",background:"linear-gradient(135deg,#1a1a2e,#0d0d1a)",display:"flex",alignItems:"center",justifyContent:"center"}}><VaultMark size={80} color={glowColor}/></div>}
        {/* Gradient overlay bottom */}
        <div style={{position:"absolute",inset:0,background:"linear-gradient(to bottom,rgba(0,0,0,0.3) 0%,transparent 30%,transparent 50%,rgba(0,0,0,0.85) 100%)"}}/>
        {/* Glow border */}
        <div style={{position:"absolute",inset:0,boxShadow:`inset 0 0 60px ${glowColor}22`,pointerEvents:"none"}}/>
      </div>

      {/* Top controls */}
      <div style={{position:"absolute",top:0,left:0,right:0,display:"flex",justifyContent:"space-between",alignItems:"center",padding:"calc(20px + var(--sat, 44px)) 20px 16px",zIndex:20}}>
        <button onClick={onClose} style={{width:42,height:42,borderRadius:"50%",background:"#000000bb",backdropFilter:"blur(12px)",border:"1px solid #ffffff20",color:"#fff",fontSize:18,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button>
        <button onClick={onEdit} style={{background:"#00000066",backdropFilter:"blur(8px)",border:"1px solid #ffffff30",borderRadius:20,padding:"8px 18px",color:"#fff",fontSize:12,cursor:"pointer",letterSpacing:1}}>Editar</button>
      </div>

      {/* Card name overlay (bottom of image, above sheet) */}
      {!sheetOpen && (
        <div style={{position:"absolute",bottom:"24vh",left:0,right:0,padding:"0 24px",zIndex:15,pointerEvents:"none"}}>
          <h2 style={{margin:"0 0 4px",fontSize:26,fontWeight:900,color:"#fff",textShadow:"0 2px 20px #000"}}>{card.name}</h2>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            <span style={{fontSize:12,color:glowColor,fontWeight:700,textShadow:`0 0 12px ${glowColor}`}}>✦ {card.rarity}</span>
            {card.category&&<span style={{fontSize:11,color:"#ffffff70"}}>· {card.category}</span>}
          </div>
        </div>
      )}

      {/* 3D Button — centered, prominent */}
      {!sheetOpen && (
        <div style={{position:"absolute",bottom:"14vh",left:0,right:0,display:"flex",justifyContent:"center",zIndex:20}}>
          <button onClick={on3D} style={{
            background:`linear-gradient(135deg,${glowColor}cc,${glowColor}88)`,
            backdropFilter:"blur(12px)",
            border:`1px solid ${glowColor}`,
            borderRadius:30,
            padding:"14px 36px",
            color:"#000",
            fontSize:15,
            fontWeight:800,
            cursor:"pointer",
            letterSpacing:2,
            boxShadow:`0 4px 30px ${glowColor}66,0 0 60px ${glowColor}22`,
            display:"flex",
            alignItems:"center",
            gap:10,
          }}>
            <span style={{fontSize:20}}>◈</span> VER EN 3D
          </button>
        </div>
      )}

      {/* Swipe hint */}
      {!sheetOpen && (
        <div style={{position:"absolute",bottom:"8vh",left:0,right:0,textAlign:"center",color:"#ffffff40",fontSize:10,letterSpacing:3,zIndex:15,pointerEvents:"none"}}>
          ↑ DESLIZA PARA VER INFO
        </div>
      )}

      {/* BOTTOM SHEET */}
      <div
        ref={sheetRef}
        style={{position:"absolute",bottom:0,left:0,right:0,height:sheetOpen?"88vh":"10vh",background:T.sheet,backdropFilter:"blur(20px)",borderRadius:"22px 22px 0 0",transition:"height 0.4s cubic-bezier(0.32,0.72,0,1)",overflow:"hidden",zIndex:25,boxShadow:"0 -8px 40px #00000088"}}
        onTouchStart={onSheetTouchStart}
        onTouchEnd={onSheetTouchEnd}
      >
        {/* Handle */}
        <div style={{display:"flex",justifyContent:"center",padding:"10px 0 6px",cursor:"pointer"}} onClick={()=>setSheetOpen(s=>!s)}>
          <div style={{width:40,height:4,borderRadius:2,background:"#ffffff30"}}/>
        </div>

        <div style={{overflowY:sheetOpen?"auto":"hidden",height:"calc(100% - 24px)",padding:"0 20px"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16}}>
            <div>
              <h2 style={{margin:"0 0 4px",fontSize:22,fontWeight:800,color:T.text}}>{card.name}</h2>
              {card.category&&<div style={{fontSize:11,color:T.textMuted,letterSpacing:2}}>{card.category.toUpperCase()}{card.subcategory?` · ${card.subcategory}`:""}</div>}
            </div>
            <button onClick={on3D} style={{background:`${glowColor}18`,border:`1px solid ${glowColor}55`,color:glowColor,borderRadius:10,padding:"8px 14px",fontSize:12,cursor:"pointer",whiteSpace:"nowrap",flexShrink:0,marginLeft:10,fontWeight:700}}>◈ 3D</button>
          </div>

          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>
            <div style={{background:"#ffffff09",borderRadius:14,padding:"13px 15px"}}>
              <div style={{fontSize:9,letterSpacing:3,color:T.textMuted,marginBottom:5}}>CONDICIÓN</div>
              <div style={{fontSize:15,fontWeight:700,color:T.text}}>{card.condition?.split(" ")[0]||"—"}</div>
              {card.condition&&<div style={{fontSize:10,color:T.textMuted,marginTop:2}}>{card.condition}</div>}
            </div>
            <div style={{background:`${glowColor}12`,borderRadius:14,padding:"13px 15px",border:`1px solid ${glowColor}30`}}>
              <div style={{fontSize:9,letterSpacing:3,color:`${glowColor}99`,marginBottom:5}}>RAREZA</div>
              <div style={{fontSize:15,fontWeight:700,color:glowColor}}>{card.rarity}</div>
            </div>
          </div>

          <div style={{background:"#ffffff06",borderRadius:14,overflow:"hidden",marginBottom:14}}>
            {[["Set / Expansión",card.set||"—"],["Cantidad",card.quantity||1],["Colección",card.collection||"—"],["Añadida",date],...(card.notes?[["Notas",card.notes]]:[])].map(([k,v],i,arr)=>(
              <div key={k} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"11px 15px",borderBottom:i<arr.length-1?"1px solid #ffffff08":"none"}}>
                <span style={{fontSize:11,color:T.textMuted,letterSpacing:1}}>{k.toUpperCase()}</span>
                <span style={{fontSize:13,color:T.pill,maxWidth:"55%",textAlign:"right"}}>{v}</span>
              </div>
            ))}
          </div>

          <div style={{background:"#ffffff04",border:`1px solid ${T.accent}10`,borderRadius:14,padding:"13px 15px",marginBottom:18}}>
            <div style={{fontSize:9,color:T.textMuted,letterSpacing:3,marginBottom:4}}>VALOR DE MERCADO</div>
            <div style={{fontSize:12,color:T.textMuted,opacity:0.5}}>Próximamente · TCGPlayer · Cardmarket · eBay</div>
          </div>

          {confirmDel?(
            <div style={{textAlign:"center",paddingBottom:40}}>
              <div style={{color:"#ff6b6b",marginBottom:12,fontSize:14}}>¿Eliminar esta carta?</div>
              <button onClick={onDelete} style={{width:"100%",padding:13,borderRadius:12,border:"none",background:"#ff4444",color:"#fff",fontSize:14,cursor:"pointer",marginBottom:10}}>Sí, eliminar</button>
              <button onClick={()=>setConfirmDel(false)} style={{width:"100%",padding:12,borderRadius:12,border:"1px solid #ffffff18",background:"transparent",color:"#8a7a6a",fontSize:14,cursor:"pointer"}}>Cancelar</button>
            </div>
          ):(
            <button onClick={()=>setConfirmDel(true)} style={{width:"100%",padding:12,borderRadius:12,border:"1px solid #ff6b6b22",background:"transparent",color:"#ff6b6b55",fontSize:13,cursor:"pointer",marginBottom:40}}>🗑 Eliminar del vault</button>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── CARD FORM ────────────────────────────────────────────────────────────────
function CardForm({ initial, onSave, onClose, title, categories, collections, rarities, T }) {
  const [name,setName]=useState(initial?.name||"");
  const [collectionId,setCollectionId]=useState(initial?.collectionId||"");
  const [categoryId,setCategoryId]=useState(initial?.categoryId||"");
  const [subcategory,setSubcategory]=useState(initial?.subcategory||"");
  const [rarity,setRarity]=useState(initial?.rarity||rarities[0]?.label||"Común");
  const [set,setSet]=useState(initial?.set||"");
  const [condition,setCondition]=useState(initial?.condition||"Near Mint (NM)");
  const [quantity,setQuantity]=useState(initial?.quantity||"1");
  const [notes,setNotes]=useState(initial?.notes||"");
  const [imageFront,setImageFront]=useState(initial?.imageFront||null);
  const [imageBack,setImageBack]=useState(initial?.imageBack||null);
  const selCat=categories.find(c=>c.id===categoryId);
  const inp={width:"100%",background:"#ffffff07",border:`1px solid ${T.border}`,borderRadius:10,padding:"11px 14px",color:T.text,fontSize:15,marginBottom:16,boxSizing:"border-box",outline:"none"};
  const lbl={fontSize:10,letterSpacing:3,color:T.textMuted,textTransform:"uppercase",marginBottom:6,display:"block"};
  const handleSave=()=>{ if(!name.trim())return; const cat=categories.find(c=>c.id===categoryId); const col=collections.find(c=>c.id===collectionId); onSave({...initial,name:name.trim(),collectionId,collection:col?.name||"",category:cat?.name||"",categoryId,subcategory,rarity,set,condition,quantity:parseInt(quantity)||1,notes,imageFront,imageBack}); };
  return (
    <div style={{position:"fixed",inset:0,background:"#000000cc",zIndex:200,display:"flex",flexDirection:"column",overflowY:"auto"}} onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div style={{background:T.bg,borderTop:`2px solid ${T.accent}44`,marginTop:"auto",borderRadius:"20px 20px 0 0",padding:"22px 20px 50px",minHeight:"85vh"}}>
        <div style={{textAlign:"center",marginBottom:22,fontSize:10,letterSpacing:5,color:T.textSub}}>{title}</div>
        <label style={lbl}>Imágenes</label>
        <div style={{display:"flex",gap:12,marginBottom:8}}><ImageSlot label="FRENTE" image={imageFront} onImage={setImageFront} icon="🖼" T={T}/><ImageSlot label="REVERSO" image={imageBack} onImage={setImageBack} icon="↩" T={T}/></div>
        <div style={{fontSize:10,color:T.textMuted,textAlign:"center",marginBottom:20}}>📷 Cámara · 🖼 Galería · 📄 PDF</div>
        <label style={lbl}>Nombre *</label>
        <input style={inp} value={name} onChange={e=>setName(e.target.value)} placeholder="Ej: Charizard, Black Lotus..."/>
        {collections.length>0&&<><label style={lbl}>Colección</label><select style={{...inp,background:T.surface}} value={collectionId} onChange={e=>setCollectionId(e.target.value)}><option value="">— Sin colección —</option>{collections.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}</select></>}
        <label style={lbl}>Categoría</label>
        <select style={{...inp,background:T.surface}} value={categoryId} onChange={e=>{setCategoryId(e.target.value);setSubcategory("");}}><option value="">— Sin categoría —</option>{categories.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}</select>
        {selCat?.subs?.length>0&&<><label style={lbl}>Subcategoría</label><select style={{...inp,background:T.surface}} value={subcategory} onChange={e=>setSubcategory(e.target.value)}><option value="">— —</option>{selCat.subs.map(s=><option key={s} value={s}>{s}</option>)}</select></>}
        <label style={lbl}>Rareza</label>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:18}}>
          {rarities.map(r=>{const sel=rarity===r.label;return(<button key={r.id} onClick={()=>setRarity(r.label)} style={{padding:"9px 4px",borderRadius:9,border:`1px solid ${sel?r.color:"#ffffff15"}`,background:sel?`${r.color}18`:"transparent",color:sel?r.color:"#555",fontSize:10,textAlign:"center",cursor:"pointer",boxShadow:sel?`0 0 12px ${r.color}55`:"none"}}>{r.label}</button>);})}</div>
        <label style={lbl}>Set / Expansión</label><input style={inp} value={set} onChange={e=>setSet(e.target.value)} placeholder="Ej: Alpha, Base Set..."/>
        <label style={lbl}>Condición</label><select style={{...inp,background:T.surface}} value={condition} onChange={e=>setCondition(e.target.value)}>{CONDITIONS.map(c=><option key={c}>{c}</option>)}</select>
        <label style={lbl}>Cantidad</label><input style={inp} type="number" min="1" value={quantity} onChange={e=>setQuantity(e.target.value)}/>
        <label style={lbl}>Notas</label><input style={inp} value={notes} onChange={e=>setNotes(e.target.value)} placeholder="Foil, firmada, idioma..."/>
        <button onClick={handleSave} style={{width:"100%",padding:15,borderRadius:12,border:"none",background:T.accentGrad,color:"#0a0a0f",fontSize:15,fontWeight:700,cursor:"pointer",marginBottom:10}}>✦ Guardar en vault</button>
        <button onClick={onClose} style={{width:"100%",padding:13,borderRadius:12,border:`1px solid ${T.border}`,background:"transparent",color:T.textMuted,fontSize:14,cursor:"pointer"}}>Cancelar</button>
      </div>
    </div>
  );
}

// ─── COLLECTION LIST ──────────────────────────────────────────────────────────
function CollectionScreen({ cards, collections, setCollections, onViewCollection, T }) {
  const [showNew,setShowNew]=useState(false);
  const [newName,setNewName]=useState(""); const [newDesc,setNewDesc]=useState("");
  const [newCover,setNewCover]=useState(null);
  const coverRef=useRef();
  const handleCoverFile=async e=>{ const file=e.target.files[0]; if(!file) return; const img=await fileToImage(file); if(img) setNewCover(img); e.target.value=""; };
  const create=()=>{ if(!newName.trim())return; setCollections([...collections,{id:`col_${Date.now()}`,name:newName.trim(),desc:newDesc.trim(),cover:newCover||null,createdAt:new Date().toISOString()}]); setNewName("");setNewDesc("");setNewCover(null);setShowNew(false); };
  const cover=(colId)=>{ const col=collections.find(c=>c.id===colId); if(col?.cover) return col.cover; const c=cards.find(c=>c.collectionId===colId&&c.imageFront); return c?.imageFront||null; };
  const count=(colId)=>cards.filter(c=>c.collectionId===colId).length;
  const uncategorized=cards.filter(c=>!c.collectionId).length;
  return (
    <div style={{paddingBottom:"calc(100px + var(--sab, 20px))"}}>
      <div style={{padding:"calc(56px + var(--sat, 44px)) 20px 20px",display:"flex",alignItems:"center",gap:12}}>
        <VaultLogo size={42}/>
        <h1 style={{margin:0,fontSize:28,fontWeight:900,letterSpacing:-0.5}}>
          <span style={{color:T.accent}}>CÉSAR'S</span> VAULT
        </h1>
      </div>
      {uncategorized>0&&<div onClick={()=>onViewCollection(null)} style={{margin:"0 20px 14px",background:T.surface2,border:`1px solid ${T.border}`,borderRadius:16,padding:16,cursor:"pointer",display:"flex",alignItems:"center",gap:14}}>
        <div style={{width:50,height:50,borderRadius:12,background:"#ffffff10",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0}}>📦</div>
        <div><div style={{fontSize:15,fontWeight:700,color:T.text}}>Sin colección</div><div style={{fontSize:12,color:T.textMuted,marginTop:2}}>{uncategorized} cartas</div></div>
        <div style={{marginLeft:"auto",color:T.textMuted,fontSize:20}}>›</div>
      </div>}
      {collections.length===0&&uncategorized===0?(
        <div style={{display:"flex",flexDirection:"column",alignItems:"center",padding:"70px 20px",gap:16,textAlign:"center"}}>
          <VaultMark size={64} color={T.accent}/>
          <div style={{fontSize:18,fontWeight:700,color:T.textMuted}}>Tu vault está vacío</div>
          <div style={{fontSize:13,color:T.textMuted,opacity:0.6}}>Crea una colección y añade tus cartas</div>
          <button onClick={()=>setShowNew(true)} style={{marginTop:8,padding:"12px 28px",borderRadius:24,border:"none",background:T.accentGrad,color:"#0a0a0f",fontSize:14,fontWeight:700,cursor:"pointer"}}>+ Nueva colección</button>
        </div>
      ):(
        <div style={{padding:"0 20px",display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
          {collections.map(col=>(
            <div key={col.id} onClick={()=>onViewCollection(col)} style={{borderRadius:18,overflow:"hidden",cursor:"pointer",background:T.card,border:`1px solid ${T.border}`}}>
              <div style={{height:110,background:cover(col.id)?"transparent":`linear-gradient(135deg,${T.accent}18,${T.accent2}0a)`,position:"relative",overflow:"hidden"}}>
                {cover(col.id)?<img src={cover(col.id)} style={{width:"100%",height:"100%",objectFit:"cover"}}/>:<div style={{width:"100%",height:"100%",display:"flex",alignItems:"center",justifyContent:"center"}}><VaultMark size={36} color={T.accent}/></div>}
                <div style={{position:"absolute",inset:0,background:"linear-gradient(to bottom,transparent 40%,#00000088 100%)"}}/>
                <div style={{position:"absolute",bottom:8,right:10,background:"#000000aa",borderRadius:8,padding:"3px 8px",fontSize:10,color:T.accent,fontWeight:700}}>{count(col.id)} {count(col.id)===1?"carta":"cartas"}</div>
              </div>
              <div style={{padding:"10px 12px"}}>
                <div style={{fontSize:13,fontWeight:700,color:T.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{col.name}</div>
                {col.desc&&<div style={{fontSize:10,color:T.textMuted,marginTop:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{col.desc}</div>}
              </div>
            </div>
          ))}
          <div onClick={()=>setShowNew(true)} style={{borderRadius:18,cursor:"pointer",background:"transparent",border:`2px dashed ${T.border}`,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",minHeight:160,gap:8}}>
            <div style={{fontSize:28,color:T.textMuted,opacity:0.4}}>+</div>
            <div style={{fontSize:12,color:T.textMuted,opacity:0.4}}>Nueva colección</div>
          </div>
        </div>
      )}
      {showNew&&(
        <div style={{position:"fixed",inset:0,background:"#000000cc",zIndex:200,display:"flex",flexDirection:"column"}} onClick={e=>e.target===e.currentTarget&&setShowNew(false)}>
          <div style={{background:T.bg,borderTop:`2px solid ${T.accent}44`,marginTop:"auto",borderRadius:"20px 20px 0 0",padding:"24px 20px 48px"}}>
            <div style={{textAlign:"center",marginBottom:20,fontSize:10,letterSpacing:5,color:T.textSub}}>NUEVA COLECCIÓN</div>
            <input style={{width:"100%",background:"#ffffff07",border:`1px solid ${T.border}`,borderRadius:10,padding:"11px 14px",color:T.text,fontSize:15,marginBottom:16,boxSizing:"border-box",outline:"none"}} value={newName} onChange={e=>setNewName(e.target.value)} placeholder="Ej: Mundial Panini 2026..."/>
            <input style={{width:"100%",background:"#ffffff07",border:`1px solid ${T.border}`,borderRadius:10,padding:"11px 14px",color:T.text,fontSize:15,marginBottom:16,boxSizing:"border-box",outline:"none"}} value={newDesc} onChange={e=>setNewDesc(e.target.value)} placeholder="Descripción (opcional)..."/>
            <div style={{marginBottom:20}}>
              <div style={{fontSize:10,letterSpacing:3,color:T.textMuted,marginBottom:8}}>PORTADA (OPCIONAL)</div>
              <div onClick={()=>coverRef.current.click()} style={{height:80,borderRadius:12,border:`2px dashed ${newCover?T.accent+"55":"#ffffff18"}`,overflow:"hidden",cursor:"pointer",position:"relative",background:"#0a0a14",display:"flex",alignItems:"center",justifyContent:"center"}}>
                {newCover?<><img src={newCover} style={{width:"100%",height:"100%",objectFit:"cover"}}/><div style={{position:"absolute",inset:0,background:"#00000044",display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontSize:12}}>Cambiar portada</div></>:<div style={{textAlign:"center",color:"#3a3a5a",fontSize:12}}>📷 Añadir portada</div>}
              </div>
              <input ref={coverRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleCoverFile}/>
            </div>
            <button onClick={create} style={{width:"100%",padding:15,borderRadius:12,border:"none",background:T.accentGrad,color:"#0a0a0f",fontSize:15,fontWeight:700,cursor:"pointer",marginBottom:10}}>✦ Crear colección</button>
            <button onClick={()=>setShowNew(false)} style={{width:"100%",padding:13,borderRadius:12,border:`1px solid ${T.border}`,background:"transparent",color:T.textMuted,fontSize:14,cursor:"pointer"}}>Cancelar</button>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── CARDS IN COLLECTION ──────────────────────────────────────────────────────
function CardsInCollection({ collection, cards, rarities, onBack, onView, onUpdateCollection, T }) {
  const colCards=collection?cards.filter(c=>c.collectionId===collection.id):cards.filter(c=>!c.collectionId);
  const coverRef2=useRef();
  const handleCover2=async e=>{ const file=e.target.files[0]; if(!file||!collection) return; const img=await fileToImage(file); if(img&&onUpdateCollection) onUpdateCollection({...collection,cover:img}); e.target.value=""; };
  const hasCover=!!collection?.cover;
  return (
    <div style={{paddingBottom:"calc(100px + var(--sab, 20px))"}}>
      {hasCover&&<div style={{height:160,position:"relative",overflow:"hidden",marginBottom:-60}}><img src={collection.cover} style={{width:"100%",height:"100%",objectFit:"cover"}}/><div style={{position:"absolute",inset:0,background:"linear-gradient(to bottom,rgba(0,0,0,0.2) 0%,rgba(0,0,0,0.85) 100%)"}}/></div>}
      <div style={{padding:`calc(${hasCover?"70px":"16px"} + var(--sat, 44px)) 20px 16px`,display:"flex",alignItems:"center",gap:14,position:"sticky",top:0,background:hasCover?"transparent":`${T.bg}ee`,backdropFilter:"blur(10px)",zIndex:10}}>
        <button onClick={onBack} style={{width:36,height:36,borderRadius:"50%",background:"#000000aa",backdropFilter:"blur(8px)",border:"1px solid #ffffff20",color:"#fff",fontSize:20,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>←</button>
        <div style={{flex:1,minWidth:0}}><div style={{fontSize:17,fontWeight:700,color:hasCover?"#fff":T.text,textShadow:hasCover?"0 1px 8px #000":""}}>{collection?.name||"Sin colección"}</div><div style={{fontSize:11,color:hasCover?"#ffffff88":T.textMuted}}>{colCards.length} cartas</div></div>
        {collection&&<><button onClick={()=>coverRef2.current.click()} style={{background:"#000000aa",backdropFilter:"blur(8px)",border:"1px solid #ffffff30",borderRadius:8,padding:"6px 10px",color:"#fff",fontSize:11,cursor:"pointer",whiteSpace:"nowrap",flexShrink:0}}>📷</button><input ref={coverRef2} type="file" accept="image/*" style={{display:"none"}} onChange={handleCover2}/></>}
      </div>
      {colCards.length===0?(
        <div style={{display:"flex",flexDirection:"column",alignItems:"center",padding:"60px 20px",gap:12,textAlign:"center"}}><div style={{fontSize:48}}>🃏</div><div style={{fontSize:16,fontWeight:700,color:T.textMuted}}>Sin cartas</div><div style={{fontSize:13,color:T.textMuted,opacity:0.6}}>Pulsa ✦ para añadir cartas</div></div>
      ):(
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,padding:"0 20px"}}>
          {colCards.map(card=>{
            const rd=rarities.find(r=>r.label===card.rarity)||{color:"#333",label:"—"};
            return(<div key={card.id} style={{background:T.card,border:`1px solid ${rd.color}`,borderRadius:14,overflow:"hidden",cursor:"pointer",boxShadow:`0 0 12px ${rd.color}22`}} onClick={()=>onView(card)}>
              <div style={{position:"relative"}}>
                {card.imageFront?<img src={card.imageFront} style={{width:"100%",aspectRatio:"2.5/3.5",objectFit:"cover",display:"block"}}/>:<div style={{width:"100%",aspectRatio:"2.5/3.5",background:"linear-gradient(135deg,#1a1a2e,#0d0d1a)",display:"flex",alignItems:"center",justifyContent:"center"}}><VaultMark size={36} color={T.accent}/></div>}
                {card.imageBack&&<div style={{position:"absolute",bottom:6,right:6,background:"#000000aa",borderRadius:6,padding:"2px 6px",fontSize:9,color:T.accent,letterSpacing:1}}>3D</div>}
              </div>
              <div style={{padding:"8px 10px"}}>
                <div style={{fontSize:13,fontWeight:700,color:T.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{card.name}</div>
                <div style={{fontSize:10,color:rd.color,marginTop:2,fontWeight:600}}>{card.rarity}</div>
              </div>
            </div>);
          })}
        </div>
      )}
    </div>
  );
}

// ─── SEARCH TAB ───────────────────────────────────────────────────────────────
function SearchTab({ cards, rarities, onView, T }) {
  const [search,setSearch]=useState("");
  const ref=useRef();
  useEffect(()=>{ setTimeout(()=>ref.current?.focus(),150); },[]);
  const results=search.trim()?cards.filter(c=>c.name?.toLowerCase().includes(search.toLowerCase())||(c.set||"").toLowerCase().includes(search.toLowerCase())||(c.category||"").toLowerCase().includes(search.toLowerCase())):[];
  return (
    <div style={{padding:`calc(24px + var(--sat, 44px)) 20px calc(100px + var(--sab, 20px))`}}>
      <h2 style={{margin:"0 0 20px",fontSize:26,fontWeight:900,color:T.text}}>Buscar</h2>
      <div style={{position:"relative",marginBottom:20}}>
        <span style={{position:"absolute",left:14,top:"50%",transform:"translateY(-50%)",color:T.textMuted,fontSize:16}}>⌕</span>
        <input ref={ref} style={{width:"100%",background:T.surface2,border:`1px solid ${T.border}`,borderRadius:14,padding:"13px 14px 13px 40px",color:T.text,fontSize:16,outline:"none",boxSizing:"border-box"}} placeholder="Nombre, set, categoría..." value={search} onChange={e=>setSearch(e.target.value)}/>
      </div>
      {!search.trim()?(
        <div style={{textAlign:"center",padding:"40px 0",color:T.textMuted,opacity:0.5}}><div style={{fontSize:40,marginBottom:10}}>⌕</div><div style={{fontSize:14}}>Escribe para buscar en tu vault</div><div style={{fontSize:12,marginTop:6}}>{cards.length} cartas en total</div></div>
      ):results.length===0?(
        <div style={{textAlign:"center",padding:"40px 0",color:T.textMuted,opacity:0.5}}><VaultMark size={48} color={T.textMuted}/><div style={{fontSize:14,marginTop:12}}>Sin resultados para "{search}"</div></div>
      ):(
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          {results.map(card=>{const rd=rarities.find(r=>r.label===card.rarity)||{color:"#333"};return(<div key={card.id} style={{background:T.card,border:`1px solid ${rd.color}`,borderRadius:14,overflow:"hidden",cursor:"pointer",boxShadow:`0 0 12px ${rd.color}22`}} onClick={()=>onView(card)}><div style={{position:"relative"}}>{card.imageFront?<img src={card.imageFront} style={{width:"100%",aspectRatio:"2.5/3.5",objectFit:"cover",display:"block"}}/>:<div style={{width:"100%",aspectRatio:"2.5/3.5",background:"#1a1a2e",display:"flex",alignItems:"center",justifyContent:"center"}}><VaultMark size={36} color={T.accent}/></div>}</div><div style={{padding:"8px 10px"}}><div style={{fontSize:13,fontWeight:700,color:T.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{card.name}</div><div style={{fontSize:10,color:rd.color,marginTop:2,fontWeight:600}}>{card.rarity}</div></div></div>);})}
        </div>
      )}
    </div>
  );
}

// ─── SETTINGS TAB ─────────────────────────────────────────────────────────────
function SettingsTab({ categories, setCategories, rarities, setRarities, currentTheme, onTheme, T }) {
  const [section,setSection]=useState(null);
  const [newCatName,setNewCatName]=useState(""); const [newSubName,setNewSubName]=useState(""); const [addingSubFor,setAddingSubFor]=useState(null);
  const [editRarityId,setEditRarityId]=useState(null); const [newRarityLabel,setNewRarityLabel]=useState(""); const [newRarityColor,setNewRarityColor]=useState("");
  const inp={width:"100%",background:"#ffffff07",border:`1px solid ${T.border}`,borderRadius:10,padding:"10px 14px",color:T.text,fontSize:14,outline:"none",boxSizing:"border-box"};

  const addCat=()=>{ if(!newCatName.trim())return; setCategories([...categories,{id:`cat_${Date.now()}`,name:newCatName.trim(),subs:[]}]); setNewCatName(""); };
  const deleteCat=(id)=>setCategories(categories.filter(c=>c.id!==id));
  const addSub=(catId)=>{ if(!newSubName.trim())return; setCategories(categories.map(c=>c.id===catId?{...c,subs:[...c.subs,newSubName.trim()]}:c)); setNewSubName("");setAddingSubFor(null); };
  const deleteSub=(catId,sub)=>setCategories(categories.map(c=>c.id===catId?{...c,subs:c.subs.filter(s=>s!==sub)}:c));

  const startEditRarity=(r)=>{ setEditRarityId(r.id); setNewRarityLabel(r.label); setNewRarityColor(r.color); };
  const saveRarity=()=>{ setRarities(rarities.map(r=>r.id===editRarityId?{...r,label:newRarityLabel,color:newRarityColor}:r)); setEditRarityId(null); };
  const addRarity=()=>{ const id=`r_${Date.now()}`; setRarities([...rarities,{id,label:"Nueva",color:"#ffffff"}]); startEditRarity({id,label:"Nueva",color:"#ffffff"}); };
  const deleteRarity=(id)=>setRarities(rarities.filter(r=>r.id!==id));

  const BackBtn=()=>(<button onClick={()=>setSection(null)} style={{width:36,height:36,borderRadius:"50%",background:"#ffffff14",border:"none",color:T.text,fontSize:20,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>←</button>);

  if(section==="themes") return (
    <div style={{padding:`calc(24px + var(--sat, 44px)) 20px calc(100px + var(--sab, 20px))`}}>
      <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:24}}><BackBtn/><h2 style={{margin:0,fontSize:22,fontWeight:800,color:T.text}}>Temas</h2></div>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        <div style={{marginBottom:12}}>
          <div style={{fontSize:10,letterSpacing:3,color:T.textMuted,marginBottom:10}}>GRATIS</div>
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {Object.entries(THEMES).filter(([,t])=>!t.premium).map(([key,theme])=>{
            const active=currentTheme===key;
            return(<div key={key} onClick={()=>onTheme(key)} style={{borderRadius:16,overflow:"hidden",border:`2px solid ${active?theme.accent:"transparent"}`,cursor:"pointer",boxShadow:active?`0 0 24px ${theme.accent}33`:"",transition:"all 0.2s"}}>
              <div style={{height:72,background:theme.bg,backgroundImage:theme.bgGrad,display:"flex",alignItems:"center",padding:"0 18px",gap:14}}>
                <span style={{fontSize:26}}>{theme.emoji}</span>
                <div style={{flex:1,display:"flex",gap:6,alignItems:"center"}}><div style={{width:50,height:8,borderRadius:4,background:theme.accent}}/><div style={{width:30,height:8,borderRadius:4,background:theme.accent2}}/></div>
                <div style={{width:24,height:24,borderRadius:"50%",border:`2px solid ${active?theme.accent:"#ffffff30"}`,background:active?theme.accent:"transparent",display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,color:"#0a0a0f",fontWeight:700}}>{active?"✓":""}</div>
              </div>
              <div style={{background:theme.surface,padding:"10px 18px",display:"flex",justifyContent:"space-between",alignItems:"center"}}><div style={{fontSize:14,fontWeight:700,color:theme.text}}>{theme.name}</div>{active&&<span style={{fontSize:10,color:theme.accent,letterSpacing:2}}>ACTIVO</span>}</div>
            </div>);
          })}
          </div>
        </div>
        <div>
          <div style={{fontSize:10,letterSpacing:3,color:T.textMuted,marginBottom:10}}>✦ PREMIUM</div>
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {Object.entries(THEMES).filter(([,t])=>t.premium).map(([key,theme])=>{
            const active=currentTheme===key;
            return(<div key={key} onClick={()=>onTheme(key)} style={{borderRadius:16,overflow:"hidden",border:`2px solid ${active?theme.accent:"#ffffff10"}`,cursor:"pointer",boxShadow:active?`0 0 28px ${theme.accent}44`:"",transition:"all 0.2s",position:"relative"}}>
              <div style={{position:"absolute",top:10,right:12,background:"linear-gradient(135deg,#ffd700,#ff9f43)",borderRadius:8,padding:"2px 8px",fontSize:9,color:"#0a0a0f",fontWeight:800,letterSpacing:1,zIndex:2}}>PREMIUM</div>
              <div style={{height:72,background:theme.bg,backgroundImage:theme.bgGrad,display:"flex",alignItems:"center",padding:"0 18px",gap:14}}>
                <span style={{fontSize:26}}>{theme.emoji}</span>
                <div style={{flex:1,display:"flex",gap:6,alignItems:"center"}}><div style={{width:50,height:8,borderRadius:4,background:theme.accent}}/><div style={{width:30,height:8,borderRadius:4,background:theme.accent2}}/></div>
                <div style={{width:24,height:24,borderRadius:"50%",border:`2px solid ${active?theme.accent:"#ffffff30"}`,background:active?theme.accent:"transparent",display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,color:"#0a0a0f",fontWeight:700}}>{active?"✓":""}</div>
              </div>
              <div style={{background:theme.surface,padding:"10px 18px",display:"flex",justifyContent:"space-between",alignItems:"center"}}><div style={{fontSize:14,fontWeight:700,color:theme.text}}>{theme.name}</div>{active&&<span style={{fontSize:10,color:theme.accent,letterSpacing:2}}>ACTIVO</span>}</div>
            </div>);
          })}
          </div>
        </div>
      </div>
    </div>
  );

  if(section==="rarities") return (
    <div style={{padding:`calc(24px + var(--sat, 44px)) 20px calc(100px + var(--sab, 20px))`}}>
      <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:20}}><BackBtn/><h2 style={{margin:0,fontSize:22,fontWeight:800,color:T.text}}>Rarezas</h2></div>
      <div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:16}}>
        {rarities.map(r=>(
          <div key={r.id} style={{background:T.surface2,border:`1px solid ${r.color}44`,borderRadius:14,overflow:"hidden"}}>
            {editRarityId===r.id?(
              <div style={{padding:"14px 15px",display:"flex",flexDirection:"column",gap:10}}>
                <input style={{...inp}} value={newRarityLabel} onChange={e=>setNewRarityLabel(e.target.value)} placeholder="Nombre de rareza"/>
                <div style={{display:"flex",gap:10,alignItems:"center"}}>
                  <input type="color" value={newRarityColor} onChange={e=>setNewRarityColor(e.target.value)} style={{width:44,height:36,borderRadius:8,border:"none",cursor:"pointer",background:"none"}}/>
                  <span style={{fontSize:13,color:T.textMuted,flex:1}}>{newRarityColor}</span>
                  <button onClick={saveRarity} style={{padding:"8px 18px",borderRadius:10,border:"none",background:T.accentGrad,color:"#0a0a0f",fontWeight:700,cursor:"pointer"}}>OK</button>
                  <button onClick={()=>setEditRarityId(null)} style={{padding:"8px 12px",borderRadius:10,border:`1px solid ${T.border}`,background:"transparent",color:T.textMuted,cursor:"pointer"}}>✕</button>
                </div>
              </div>
            ):(
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"13px 15px"}}>
                <div style={{display:"flex",alignItems:"center",gap:10}}>
                  <div style={{width:14,height:14,borderRadius:"50%",background:r.color,boxShadow:`0 0 8px ${r.color}88`,flexShrink:0}}/>
                  <div style={{fontSize:14,fontWeight:700,color:r.color}}>{r.label}</div>
                </div>
                <div style={{display:"flex",gap:8}}>
                  <button onClick={()=>startEditRarity(r)} style={{padding:"5px 11px",borderRadius:8,border:`1px solid ${T.accent}44`,background:`${T.accent}14`,color:T.accent,fontSize:11,cursor:"pointer"}}>Editar</button>
                  <button onClick={()=>deleteRarity(r.id)} style={{padding:"5px 9px",borderRadius:8,border:"1px solid #ff6b6b33",background:"transparent",color:"#ff6b6b66",fontSize:13,cursor:"pointer"}}>🗑</button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
      <button onClick={addRarity} style={{width:"100%",padding:12,borderRadius:12,border:`1px dashed ${T.accent}44`,background:"transparent",color:T.accent,fontSize:13,cursor:"pointer"}}>+ Nueva rareza</button>
    </div>
  );

  if(section==="categories") return (
    <div style={{padding:`calc(24px + var(--sat, 44px)) 20px calc(100px + var(--sab, 20px))`}}>
      <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:20}}><BackBtn/><h2 style={{margin:0,fontSize:22,fontWeight:800,color:T.text}}>Categorías</h2></div>
      <div style={{background:T.surface2,border:`1px solid ${T.border}`,borderRadius:14,padding:16,marginBottom:18}}>
        <div style={{fontSize:10,letterSpacing:2,color:T.textMuted,marginBottom:10}}>NUEVA CATEGORÍA</div>
        <div style={{display:"flex",gap:8}}><input style={{...inp,flex:1}} value={newCatName} onChange={e=>setNewCatName(e.target.value)} placeholder="Nombre..." onKeyDown={e=>e.key==="Enter"&&addCat()}/><button onClick={addCat} style={{padding:"10px 16px",borderRadius:10,border:"none",background:T.accentGrad,color:"#0a0a0f",fontWeight:700,cursor:"pointer",fontSize:13,whiteSpace:"nowrap"}}>+ Añadir</button></div>
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:10}}>
        {categories.map(cat=>(
          <div key={cat.id} style={{background:T.surface2,border:`1px solid ${T.border}`,borderRadius:14,overflow:"hidden"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"13px 15px"}}>
              <div><div style={{fontSize:14,fontWeight:700,color:T.text}}>{cat.name}</div><div style={{fontSize:11,color:T.textMuted,marginTop:1}}>{cat.subs.length} subcategorías</div></div>
              <div style={{display:"flex",gap:8}}>
                <button onClick={()=>setAddingSubFor(addingSubFor===cat.id?null:cat.id)} style={{padding:"5px 11px",borderRadius:8,border:`1px solid ${T.accent}44`,background:`${T.accent}14`,color:T.accent,fontSize:11,cursor:"pointer"}}>+ Sub</button>
                <button onClick={()=>deleteCat(cat.id)} style={{padding:"5px 9px",borderRadius:8,border:"1px solid #ff6b6b33",background:"transparent",color:"#ff6b6b66",fontSize:13,cursor:"pointer"}}>🗑</button>
              </div>
            </div>
            {cat.subs.length>0&&<div style={{padding:"0 15px 12px",display:"flex",flexWrap:"wrap",gap:7}}>{cat.subs.map(sub=>(<div key={sub} style={{display:"flex",alignItems:"center",gap:4,background:"#ffffff0a",border:"1px solid #ffffff14",borderRadius:20,padding:"4px 10px"}}><span style={{fontSize:12,color:T.pill}}>{sub}</span><button onClick={()=>deleteSub(cat.id,sub)} style={{background:"none",border:"none",color:"#ff6b6b66",fontSize:11,cursor:"pointer",padding:0}}>✕</button></div>))}</div>}
            {addingSubFor===cat.id&&<div style={{padding:"0 15px 13px",display:"flex",gap:8}}><input style={{...inp,flex:1,fontSize:13}} value={newSubName} onChange={e=>setNewSubName(e.target.value)} placeholder="Subcategoría..." onKeyDown={e=>e.key==="Enter"&&addSub(cat.id)}/><button onClick={()=>addSub(cat.id)} style={{padding:"9px 13px",borderRadius:9,border:"none",background:T.accentGrad,color:"#0a0a0f",fontWeight:700,cursor:"pointer",fontSize:12}}>OK</button></div>}
          </div>
        ))}
      </div>
    </div>
  );

  const menuItems=[
    {id:"themes",icon:"◑",title:"Temas",desc:"Apariencia de la app"},
    {id:"rarities",icon:"✦",title:"Rarezas",desc:"Edita nombres, colores y añade nuevas"},
    {id:"categories",icon:"⊞",title:"Categorías",desc:"Gestiona categorías y subcategorías"},
  ];
  return (
    <div style={{padding:`calc(24px + var(--sat, 44px)) 20px calc(100px + var(--sab, 20px))`}}>
      <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:28}}><VaultMark size={28} color={T.accent}/><h2 style={{margin:0,fontSize:26,fontWeight:900,color:T.text}}>Ajustes</h2></div>
      <div style={{display:"flex",flexDirection:"column",gap:10}}>
        {menuItems.map(item=>(
          <div key={item.id} onClick={()=>setSection(item.id)} style={{background:T.surface2,border:`1px solid ${T.border}`,borderRadius:16,padding:"16px 18px",display:"flex",alignItems:"center",gap:14,cursor:"pointer"}}>
            <div style={{width:42,height:42,borderRadius:12,background:`${T.accent}18`,border:`1px solid ${T.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,color:T.accent,flexShrink:0}}>{item.icon}</div>
            <div style={{flex:1}}><div style={{fontSize:15,fontWeight:700,color:T.text}}>{item.title}</div><div style={{fontSize:12,color:T.textMuted,marginTop:2}}>{item.desc}</div></div>
            <div style={{color:T.textMuted,fontSize:18}}>›</div>
          </div>
        ))}
      </div>
      <div style={{marginTop:28,padding:"14px 18px",background:T.surface2,border:`1px solid ${T.border}`,borderRadius:16}}>
        <div style={{fontSize:10,letterSpacing:3,color:T.textMuted,marginBottom:8}}>CÉSAR'S VAULT</div>
        <div style={{fontSize:13,color:T.textMuted,lineHeight:1.6}}>Tu gestor personal de cartas TCG. Datos guardados localmente en tu dispositivo.</div>
      </div>
    </div>
  );
}

// ─── BOTTOM NAV ───────────────────────────────────────────────────────────────
function BottomNav({ tab, setTab, T }) {
  const items = [
    { id:"collection", label:"Colección" },
    { id:"search",     label:"Buscar" },
    { id:"settings",   label:"Ajustes" },
  ];
  return (
    <div style={{position:"fixed",bottom:0,left:0,right:0,zIndex:150,background:T.navBg,backdropFilter:"blur(20px)",borderTop:`1px solid ${T.navBorder}`,display:"flex",justifyContent:"space-around",paddingTop:10,paddingBottom:"calc(28px + var(--sab, 20px))"}}>
      {items.map(item=>{
        const active=tab===item.id;
        const d = T.icons[item.id==="settings"?"settings":item.id==="search"?"search":"collection"];
        return(
          <button key={item.id} onClick={()=>setTab(item.id)} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:5,background:"none",border:"none",cursor:"pointer",padding:"4px 20px",color:active?T.accent:T.text,opacity:active?1:0.38,transition:"opacity 0.15s,color 0.15s"}}>
            <NavIcon d={d} color={active?T.accent:T.text}/>
            <span style={{fontSize:10,letterSpacing:0.5,fontWeight:active?700:400}}>{item.label}</span>
          </button>
        );
      })}
    </div>
  );
}

// ─── MAIN APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [cards,setCards]             = useState([]);
  const [collections,setCollections] = useState([]);
  const [categories,setCategories]   = useState(DEFAULT_CATEGORIES);
  const [rarities,setRarities]       = useState(DEFAULT_RARITIES);
  const [themeName,setThemeName]     = useState("cesar");
  const [loading,setLoading]         = useState(true);
  const [tab,setTab]                 = useState("collection");
  const [activeCollection,setActiveCollection] = useState(undefined);
  const [viewCard,setViewCard]       = useState(null);
  const [editCard,setEditCard]       = useState(null);
  const [show3D,setShow3D]           = useState(null);
  const [showAddCard,setShowAddCard] = useState(false);

  const T = THEMES[themeName]||THEMES.vault;

  useEffect(()=>{
    loadAll().then(({cards:c,collections:cols,settings:s})=>{
      setCards(c); setCollections(cols);
      if(s?.theme) setThemeName(s.theme);
      if(s?.categories) setCategories(s.categories);
      if(s?.rarities) setRarities(s.rarities);
      setLoading(false);
    });
  },[]);

  const persist=(c,cols,theme,cats,rars)=>{ setCards(c); saveAll(c,cols,{theme,categories:cats,rarities:rars}); };
  const handleAddCard=async(d)=>{
    const nc={...d,id:Date.now().toString(),addedAt:new Date().toISOString()};
    if(activeCollection!==undefined&&activeCollection!==null&&!nc.collectionId) nc.collectionId=activeCollection.id;
    const next=[nc,...cards]; persist(next,collections,themeName,categories,rarities); setShowAddCard(false);
  };
  const handleUpdate=async(d)=>{ const next=cards.map(c=>c.id===d.id?d:c); persist(next,collections,themeName,categories,rarities); setViewCard(d);setEditCard(null); };
  const handleDelete=async(id)=>{ const next=cards.filter(c=>c.id!==id); persist(next,collections,themeName,categories,rarities); setViewCard(null); };
  const handleCollections=(cols)=>{ setCollections(cols); saveAll(cards,cols,{theme:themeName,categories,rarities}); };
  const handleTheme=(t)=>{ setThemeName(t); saveAll(cards,collections,{theme:t,categories,rarities}); };
  const handleCategories=(cats)=>{ setCategories(cats); saveAll(cards,collections,{theme:themeName,categories:cats,rarities}); };
  const handleRarities=(rars)=>{ setRarities(rars); saveAll(cards,collections,{theme:themeName,categories,rarities:rars}); };

  if(loading) return(
    <div style={{minHeight:"100vh",background:"#0a0a0f",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:16}}>
      <VaultMark size={64} color="#ffd700"/>
      <div style={{color:"#ffd70088",fontSize:11,letterSpacing:5}}>CARGANDO VAULT...</div>
    </div>
  );

  return(
    <div style={{minHeight:"100vh",background:T.bg,backgroundImage:T.bgGrad,fontFamily:"Inter,sans-serif",color:T.text,transition:"background 0.4s"}}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');*{box-sizing:border-box;}button,input,select{font-family:Inter,sans-serif;}select option{background:#1a1a2e;color:#e8e0d5;}:root{--sat:env(safe-area-inset-top,44px);--sab:env(safe-area-inset-bottom,20px);}.__safe_top{padding-top:calc(24px + var(--sat))!important;}.__safe_top_sm{padding-top:calc(16px + var(--sat))!important;}.__nav_bottom{padding-bottom:calc(28px + var(--sab))!important;}`}</style>

      {tab==="collection"&&activeCollection===undefined&&<CollectionScreen cards={cards} collections={collections} setCollections={handleCollections} onViewCollection={col=>setActiveCollection(col)} T={T}/>}
      {tab==="collection"&&activeCollection!==undefined&&<CardsInCollection collection={activeCollection} cards={cards} rarities={rarities} onBack={()=>setActiveCollection(undefined)} onView={setViewCard} onUpdateCollection={col=>{const next=collections.map(c=>c.id===col.id?col:c);handleCollections(next);setActiveCollection(col);}} T={T}/>}
      {tab==="search"&&<SearchTab cards={cards} rarities={rarities} onView={setViewCard} onUpdateCollection={col=>{const next=collections.map(c=>c.id===col.id?col:c);handleCollections(next);setActiveCollection(col);}} T={T}/>}
      {tab==="settings"&&<SettingsTab categories={categories} setCategories={handleCategories} rarities={rarities} setRarities={handleRarities} currentTheme={themeName} onTheme={handleTheme} T={T}/>}

      <BottomNav tab={tab} setTab={t=>{setTab(t);if(t==="collection")setActiveCollection(undefined);}} T={T}/>

      {/* FAB — fixed bottom right */}
      {(tab==="collection")&&(
        <button onClick={()=>setShowAddCard(true)} style={{position:"fixed",bottom:"calc(88px + var(--sab, 20px))",right:22,width:58,height:58,borderRadius:"50%",background:T.accentGrad,border:"none",fontSize:24,color:"#0a0a0f",boxShadow:`0 4px 24px ${T.accent}66,0 0 0 1px ${T.accent}33`,cursor:"pointer",zIndex:100,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:700}}>✦</button>
      )}

      {showAddCard&&<CardForm onSave={handleAddCard} onClose={()=>setShowAddCard(false)} title="NUEVA CARTA" categories={categories} collections={collections} rarities={rarities} T={T}/>}
      {editCard&&<CardForm initial={editCard} onSave={handleUpdate} onClose={()=>setEditCard(null)} title="EDITAR CARTA" categories={categories} collections={collections} rarities={rarities} T={T}/>}
      {viewCard&&!editCard&&<CardDetail card={viewCard} onClose={()=>setViewCard(null)} onEdit={()=>setEditCard(viewCard)} onDelete={()=>handleDelete(viewCard.id)} on3D={()=>setShow3D(viewCard)} rarities={rarities} T={T}/>}
      {show3D&&<Card360Viewer front={show3D.imageFront} back={show3D.imageBack} rarityColor={(rarities.find(r=>r.label===show3D.rarity)||{color:"#ffd700"}).color} name={show3D.name} onClose={()=>setShow3D(null)}/>}
    </div>
  );
}
